// ImpressionResponse describes the response object to be returned (as JSON over HTTP) for any matches found.
type WatsonResponse struct {
	ID                   string                 `json:"request_id"`
	Error                string                 `json:"error,omitempty"`
	MatchedByLevel       string                 `json:"matched_by_level"`
	Influencers          []waterfall.Claim      `json:"influencers"`
	DiscardedInfluencers []waterfall.Claim      `json:"discarded_influencers"`
	Claims               []waterfall.Claim      `json:"claims"`
	Match                waterfall.Claim        `json:"match"`
	Request              WatsonRequest          `json:"request"`
	Log                  []*reclog.ModuleLogger `json:"log"`
}

func (w *WatsonResponse) HasRestrictedClaim() bool {
	// check match object
	if restrictedvalidation.IsRestricted(w.Match.AttributionModule()) {
		return true
	}

	// check claims
	for _, claim := range w.Claims {
		if restrictedvalidation.IsRestricted(claim.AttributionModule()) {
			return true
		}
	}

	// 11/07/2024: also check influencers and discarded influencers
	for _, influencer := range w.Influencers {
		if restrictedvalidation.IsRestricted(influencer.AttributionModule()) {
			return true
		}
	}

	// check discarded influencers
	for _, influencer := range w.DiscardedInfluencers {
		if restrictedvalidation.IsRestricted(influencer.AttributionModule()) {
			return true
		}
	}

	return false
}

func (w *WatsonResponse) ValidateUTF8() error {
	return w.validateUTF8ByKind(true, "", reflect.Value{})
}

func (w *WatsonResponse) validateUTF8ByKind(atTop bool, path string, field reflect.Value) error {
	top := reflect.ValueOf(w)

	if atTop && !field.IsValid() {
		path = "watsonResponse"
		field = top
	}

	field = reflect.Indirect(field)

	var errList error

	switch field.Kind() {
	case reflect.Array:
		fallthrough
	case reflect.Slice:
		for i := 0; i < field.Len(); i++ {
			err := w.subFieldValidateUTF8(fmt.Sprintf("%s.%d", path, i), field.Index(i))
			if err != nil {
				errList = multierr.Append(errList, err)
			}
		}
	case reflect.Map:
		iter := field.MapRange()
		for iter.Next() {
			// catch invalid map key
			err := w.subFieldValidateUTF8(fmt.Sprintf("%s.%s", path, iter.Key()), iter.Key())
			if err != nil {
				errList = multierr.Append(errList, err)
			}
			// catch invalid map value
			err = w.subFieldValidateUTF8(fmt.Sprintf("%s.%s", path, iter.Key()), iter.Value())
			if err != nil {
				errList = multierr.Append(errList, err)
			}
		}
	case reflect.Struct:
		for i := 0; i < field.NumField(); i++ {
			subField := field.Field(i)
			err := w.subFieldValidateUTF8(fmt.Sprintf("%s.%s", path, field.Type().Field(i).Name), subField)
			if err != nil {
				errList = multierr.Append(errList, err)
			}
		}
	}

	if errList != nil {
		return errList
	}

	return nil
}

func (w *WatsonResponse) subFieldValidateUTF8(path string, field reflect.Value) error {
	field = reflect.Indirect(field)
	if field.Kind() == reflect.Interface {
		field = field.Elem()
	}

	switch field.Kind() {
	case reflect.String:
		if !utf8.ValidString(field.String()) {
			return fmt.Errorf("at path \"%s\" non utf-8 string: %s", path, field.String())
		}
	case reflect.Array:
		fallthrough
	case reflect.Slice:
		fallthrough
	case reflect.Map:
		fallthrough
	case reflect.Struct:
		err := w.validateUTF8ByKind(false, path, field)
		if err != nil {
			return err
		}
	}
	return nil
}

