// ShouldEnforceAttributionMTR returns true if Attribution MTR (Minimum Time to Respond) enforcement
// should be applied based on traffic type and previous attribution status.
// MTR enforcement applies when the traffic is an event OR session AND there was
// a previous attribution that occurred too recently.
func (r *WatsonRequest) ShouldEnforceAttributionMTR() bool {
	return (r.TrafficType == "event" || r.TrafficType == "session") && r.PreviousAttributionMTREnforced
}

