import (
	"context"
	"strconv"
	"sync"

	watson "github.com/Kochava/watson-proto/go"

	"github.com/Kochava/mqa/v2/message"
	"github.com/Kochava/mqa/v2/producer"
	"github.com/golang/protobuf/proto" //nolint:staticcheck
	"go.uber.org/zap"
)

// LogTransferFailuresFunc allows kafka method to log fails in producing to influx
type LogTransferFailuresFunc func(influxSeries string, appID string)

func TODOLogTransferFailuresFunc(influxSeries string, appID string) {}

// TransferRecLogs will write rec logs
func TransferRecLogs(shutdownCtx context.Context, donkeyTopic string, waitGroup *sync.WaitGroup, logger *zap.Logger, prod producer.Producer, logChan chan *watson.Response, logDroppedRecLogsToInflux LogTransferFailuresFunc, logInvalidUTF8Values bool) {
	defer waitGroup.Done()
	inShutdownMode := false

	for protoLogItem := range logChan {
		// check if we are trying to shutdown or not
		select {
		case <-shutdownCtx.Done():
			// signal that we should no longer retry writing to logChan
			inShutdownMode = true
		default: // just here to not block
		}

		protoLogItemByteSlice, err := proto.Marshal(protoLogItem)
		if err != nil {
			logger.Warn("error converting proto payload to byte slice",
				zap.String("controlTID", protoLogItem.GetRequest().GetControlTransactionId()),
				zap.Int32("app_id", protoLogItem.GetRequest().GetAppId()),
				zap.Error(err))
			continue
		}

		// Use Watson's request_id for message ID and deduplication
		requestID := protoLogItem.GetRequestId()
		logger.Debug("pushing log",
			zap.String("topic", donkeyTopic),
			zap.String("request_id", requestID),
			zap.String("controlTID", protoLogItem.GetRequest().GetControlTransactionId()),
			zap.Int32("app_id", protoLogItem.GetRequest().GetAppId()))

		// Create MQA v2 message with request_id for idempotency
		msg := message.NewMessage(requestID, protoLogItemByteSlice)

		err = prod.Produce(msg)

		if err != nil {
			logger.Warn("error queueing reclog", zap.Int32("appid", protoLogItem.GetRequest().GetAppId()), zap.Error(err))

			// if we are trying to shut down watson, don't write to the logChan since it's closed
			if inShutdownMode {
				logger.Warn("error queueing reclog in shutdown mode - dropping log", zap.Int32("appid", protoLogItem.GetRequest().GetAppId()), zap.Error(err))
				logDroppedRecLogsToInflux("discarded_rec_log_donkey_at_cap", strconv.Itoa(int(protoLogItem.GetRequest().GetAppId())))
				continue
			}

			// not in shutdown mode so we can retry a failed message
			select {
			// retry this unless the channel is full
			case logChan <- protoLogItem:

			default:
				// log channel full and we still need to retry additional items, something is probably wrong
				// don't hold up attribution processing for rec logs, so drop it and log this happening to influx
				logger.Warn("Dumping rec logs, over capacity", zap.Int("Queue", len(logChan)), zap.Int32("app_id", protoLogItem.GetRequest().GetAppId()))
				logDroppedRecLogsToInflux("discarded_rec_log_donkey_at_cap", strconv.Itoa(int(protoLogItem.GetRequest().GetAppId())))
			}
		}
	} // end of logChan range loop
	// we will break out of here once logChan is both empty and closed
}
