// WatsonResponseToProto parses a watson response struct into a protobuf message
func WatsonResponseToProto(resp structs.WatsonResponse) (*wproto.Response, error) {

	// protoMessage is the closest we can get to a 1 to 1 mapping of a native go watson response struct
	// converted to a protobuf object. See conversionutil package for more
	protoMessage := &wproto.Response{
		RequestId:            resp.ID,
		Error:                resp.Error,
		MatchedByLevel:       resp.MatchedByLevel,
		Influencers:          conversionutil.ClaimSliceToProto(resp.Influencers),
		DiscardedInfluencers: conversionutil.ClaimSliceToProto(resp.DiscardedInfluencers),
		Claims:               conversionutil.ClaimSliceToProto(resp.Claims),
		Match:                conversionutil.SingleClaimToProto(resp.Match),
		Request:              conversionutil.WatsonRequestToProto(resp.Request),
		Log:                  conversionutil.LogSliceToPro(resp.Log),
	}

	return protoMessage, nil
}

// RestrictedWatsonResponseToProto parses a watson response struct into a protobuf message
func RestrictedWatsonResponseToProto(resp structs.WatsonResponse) (*wproto.Response, bool, error) {
	isRestricted := false

	// protoMessage is the closest we can get to a 1 to 1 mapping of a native go watson response struct
	// converted to a protobuf object. See conversionutil package for more
	matches := GetRestrictedClaims(resp.Match)
	match := waterfall.Claim{}
