		match = matches[0]
		isRestricted = true
	}
	influencers := GetRestrictedClaims(resp.Influencers...)
	isRestricted = isRestricted || len(influencers) > 0
	discardedInfluencers := GetRestrictedClaims(resp.DiscardedInfluencers...)
	isRestricted = isRestricted || len(discardedInfluencers) > 0
	claims := GetRestrictedClaims(resp.Claims...)
	isRestricted = isRestricted || len(claims) > 0

	protoMessage := &wproto.Response{
		RequestId:            resp.ID,
		Error:                resp.Error,
		MatchedByLevel:       resp.MatchedByLevel,
		Influencers:          conversionutil.ClaimSliceToProto(influencers),
		DiscardedInfluencers: conversionutil.ClaimSliceToProto(discardedInfluencers),
		Claims:               conversionutil.ClaimSliceToProto(claims),
		Match:                conversionutil.SingleClaimToProto(match),
		Request:              conversionutil.RestrictedRequestToProto(resp.Request),
		Log:                  conversionutil.LogSliceToPro(GetModuleLogs(resp.Log...)),
	}

	return protoMessage, isRestricted, nil
}

